patch:
diff --git a/llvm/lib/Transforms/Scalar/LoopStrengthReduce.cpp b/llvm/lib/Transforms/Scalar/LoopStrengthReduce.cpp
index f69db57c25ed..af1832a6952e 100644
--- a/llvm/lib/Transforms/Scalar/LoopStrengthReduce.cpp
+++ b/llvm/lib/Transforms/Scalar/LoopStrengthReduce.cpp
@@ -6885,6 +6885,18 @@ static bool SalvageDVI(llvm::Loop *L, ScalarEvolution &SE,
     assert(DVIRec.RecoveryExprs[0] &&
            "Expected a SCEVDbgSalvageBuilder for location 0");
     SCEVDbgValueBuilder *B = DVIRec.RecoveryExprs[0].get();
+    // For empty DIExpressions, ensure the builder has the LSR induction variable
+    // in its LocationOps before calling appendToVectors.
+    if (B->LocationOps.empty()) {
+      // Check if the builder actually has any expression operations.
+      // If not, salvage has failed and we should not proceed.
+      if (B->expr_ops().empty()) {
+        // Salvage failed, restore original state and return false.
+        restorePreTransformState(DVIRec);
+        return false;
+      }
+      B->pushLocation(LSRInductionVar);
+    }
     B->appendToVectors(NewExpr, NewLocationOps);
   }
   for (const auto &Op : DVIRec.Expr->expr_ops()) {

